class Trial extends DataClass implements Insertable<Trial> {
  final int id;
  final String name;
  final String? crop;
  final String? location;
  final String? season;
  final String status;

  /// Plot dimensions (e.g. "10 m × 2 m"). Trial-level default.
  final String? plotDimensions;

  /// Number of rows per plot. Trial-level default.
  final int? plotRows;

  /// Spacing between plots (e.g. "0.5 m"). Trial-level default.
  final String? plotSpacing;
  final String? sponsor;
  final String? protocolNumber;
  final String? investigatorName;
  final String? cooperatorName;
  final String? siteId;
  final String? fieldName;
  final String? county;
  final String? stateProvince;
  final String? country;
  final double? latitude;
  final double? longitude;
  final double? elevationM;
  final String? experimentalDesign;
  final double? plotLengthM;
  final double? plotWidthM;
  final double? alleyLengthM;
  final String? previousCrop;
  final String? tillage;
  final bool? irrigated;
  final String? soilSeries;
  final String? soilTexture;
  final double? organicMatterPct;
  final double? soilPh;
  final DateTime? harvestDate;
  final String? studyType;

  /// Workspace type: variety | efficacy | glp | standalone
  final String workspaceType;
  final DateTime createdAt;
  final DateTime updatedAt;
  final bool isDeleted;
  final DateTime? deletedAt;
  final String? deletedBy;
  final bool isArmLinked;
  final DateTime? armImportedAt;
  final String? armSourceFile;
  final String? armVersion;

  /// Session used for ARM import ratings; preferred for Rating Shell export.
  /// Plain int (no FK) to avoid Drift circular ref: sessions already reference trials.
  final int? armImportSessionId;
  const Trial(
      {required this.id,
      required this.name,
      this.crop,
      this.location,
      this.season,
      required this.status,
      this.plotDimensions,
      this.plotRows,
      this.plotSpacing,
      this.sponsor,
      this.protocolNumber,
      this.investigatorName,
      this.cooperatorName,
      this.siteId,
      this.fieldName,
      this.county,
      this.stateProvince,
      this.country,
      this.latitude,
      this.longitude,
      this.elevationM,
      this.experimentalDesign,
      this.plotLengthM,
      this.plotWidthM,
      this.alleyLengthM,
      this.previousCrop,
      this.tillage,
      this.irrigated,
      this.soilSeries,
      this.soilTexture,
      this.organicMatterPct,
      this.soilPh,
      this.harvestDate,
      this.studyType,
      required this.workspaceType,
      required this.createdAt,
      required this.updatedAt,
      required this.isDeleted,
      this.deletedAt,
      this.deletedBy,
      required this.isArmLinked,
      this.armImportedAt,
      this.armSourceFile,
      this.armVersion,
      this.armImportSessionId});
