class Plot extends DataClass implements Insertable<Plot> {
  final int id;
  final int trialId;
  final String plotId;
  final int? plotSortIndex;
  final int? rep;
  final int? treatmentId;
  final String? row;
  final String? column;
  final int? fieldRow;
  final int? fieldColumn;
  final String? notes;

  /// Assignment provenance: 'imported' | 'manual' | null (unknown).
  final String? assignmentSource;
  final DateTime? assignmentUpdatedAt;
  final double? plotLengthM;
  final double? plotWidthM;
  final double? plotAreaM2;
  final double? harvestLengthM;
  final double? harvestWidthM;
  final double? harvestAreaM2;
  final String? plotDirection;
  final String? soilSeries;
  final String? plotNotes;

  /// Field layout: non-data / border plot.
  /// v2: excluded from rating queue by default; display + editing unchanged in Plots tab.
  final bool isGuardRow;
  final bool isDeleted;
  final DateTime? deletedAt;
  final String? deletedBy;
  final bool excludeFromAnalysis;
  final String? exclusionReason;
  final String? damageType;

  /// Canonical ARM plot number (matches Rating Shell plot column); nullable for non-ARM plots.
  final int? armPlotNumber;

  /// Index into source ARM CSV data rows for this plot row (import alignment).
  final int? armImportDataRowIndex;
